d, auth.PasswordHash))            throw new UnauthorizedException("Invalid login or password.");        User? user = await userRepository.FindAsync(auth.UserId).ConfigureAwait(false)                     ?? throw new UnauthorizedException("Invalid login or password.");        if (user.Status is not UserStatus.Active)            throw new ForbiddenException("User account is inactive.");        return await TokenIssueHelper.IssueAsync(                user,                tokenIssuer,                refreshTokenRepository,                idGenerator,                this._refreshTokenOptions)            .ConfigureAwait(false);    }}